Steps:
[AUTH role=ORG_USER]
[GQL-OP setup_me]
  query { me { id } }
[GQL-EXEC setup_me]
[GQL-CAPTURE setup_me.data.me.id → USER_ID]
[GQL-OP cleanup_pre]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_pre]
[GQL-OP get_def]
  query { productConfiguration(configurableProductId: "@td(CFG_LAPTOP.id)" storeId: "{{STORE_ID}}") { configurationSections { id options { product { id } } } } }
[GQL-EXEC get_def]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.id → SECTION_RAM_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.0.options.0.product.id → OPT_RAM_BASE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.id → SECTION_STORAGE_ID]
[GQL-CAPTURE get_def.data.productConfiguration.configurationSections.1.options.0.product.id → OPT_STORAGE_BASE_ID]
[GQL-OP add_item]
[GQL-VARS add_item] {"configurationSections": [{"sectionId": "{{SECTION_RAM_ID}}", "type": "Product", "option": {"productId": "{{OPT_RAM_BASE_ID}}", "quantity": 1}}, {"sectionId": "{{SECTION_STORAGE_ID}}", "type": "Product", "option": {"productId": "{{OPT_STORAGE_BASE_ID}}", "quantity": 1}}]}
  mutation AddItem($configurationSections: [ConfigurationSectionInput]) {
    addItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" productId: "@td(CFG_LAPTOP.id)" quantity: 1 configurationSections: $configurationSections }) {
      id itemsCount items { id quantity extendedPrice { amount } configurationItems { id sectionId productId } }
    }
  }
[GQL-EXEC add_item]
[GQL-CAPTURE add_item.data.addItem.items.0.id → LINE_ITEM_ID]
[GQL-CAPTURE add_item.data.addItem.items.0.configurationItems.0.id → ORIGINAL_CONFIG_ITEM_ID_0]
[GQL-OP reject_invalid]
[GQL-VARS reject_invalid] {"configurationSections": [{"sectionId": "00000000-0000-0000-0000-000000000000", "type": "Product", "option": {"productId": "{{OPT_RAM_BASE_ID}}", "quantity": 1}}]}
  mutation ChangeCartConfiguredItem($configurationSections: [ConfigurationSectionInput]) {
    changeCartConfiguredItem(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" lineItemId: "{{LINE_ITEM_ID}}" quantity: 1 configurationSections: $configurationSections }) {
      id validationErrors { errorCode errorMessage } items { id quantity configurationItems { id sectionId productId } }
    }
  }
[GQL-EXEC reject_invalid]
[GQL-OP read_back]
  query { configurationItems(storeId: "{{STORE_ID}}" currencyCode: "USD" lineItemId: "{{LINE_ITEM_ID}}" userId: "{{USER_ID}}") { configurationItems { id sectionId productId } } }
[GQL-EXEC read_back]
[GQL-OP cleanup_post]
  mutation { clearCart(command: { storeId: "{{STORE_ID}}" userId: "{{USER_ID}}" }) { id } }
[GQL-EXEC cleanup_post]

